sql:
SELECT AVG(effort) AS average_effort
FROM issues
WHERE type = 'BUG' AND severity = 'CRITICAL';

external_knowledge:
'Critical issues' refers to issues with a severity of 'CRITICAL'; 
'Top 3 most recurring issues' refers to the issues with the highest count of historical entries; 
'Longest history' refers to the highest count of historical entries for each issue.

sql:
SELECT COUNT(issue_id) AS updated_issues_count
  FROM issue_history
 WHERE change_type = 'updated';
